mapper.select:
SELECT COUNT(1)
FROM virtual_daily_checkin
WHERE user_id = #{userId}

SELECT checkin_id, user_id, checkin_date, day_sequence, credits_awarded, create_time
FROM virtual_daily_checkin
WHERE user_id = #{userId}
ORDER BY checkin_date DESC
LIMIT #{limit}

SELECT u.user_id, u.email, CASE WHEN COUNT(d.checkin_id) > 0 THEN GREATEST(COALESCE(u.consecutive_days, 1), 1) ELSE COALESCE(u.consecutive_days, 0) END AS current_streak, CASE WHEN COUNT(d.checkin_id) > 0 THEN GREATEST(COALESCE(u.max_streak_days, 1), 1) ELSE COALESCE(u.max_streak_days, 0) END AS max_streak_days, MAX(d.create_time) AS checkin_time, MAX(d.checkin_date) AS last_checkin_date, COUNT(d.checkin_id) AS total_checkin_days FROM virtual_user u LEFT JOIN virtual_daily_checkin d ON d.user_id = u.user_id
AND u.user_id = #{queryUserId} AND d.checkin_date >= #{beginTime} AND d.checkin_date <= #{endTime}
GROUP BY u.user_id, u.email, u.consecutive_days, u.max_streak_days HAVING COUNT(d.checkin_id) > 0 ORDER BY last_checkin_date DESC
